import{_ as a,o as t,c as s,ac as l}from"./chunks/framework.DnBnwVZk.js";const _=JSON.parse('{"title":"某服务少部分节点CPU 100%，导致局部RT飙升","description":"","frontmatter":{"date":"2022-11-27T21:56:37.000Z","categories":["经验&教训"],"tags":[null],"publish":false},"headers":[],"relativePath":"views/issue/ygc_cpu/ygcCauseCpu.md","filePath":"views/issue/ygc_cpu/ygcCauseCpu.md","lastUpdated":1775803235000}'),i={name:"views/issue/ygc_cpu/ygcCauseCpu.md"};function o(r,e,p,c,u,d){return t(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1669586197000"},[...e[0]||(e[0]=[l('<h1 id="某服务少部分节点cpu-100-导致局部rt飙升" tabindex="-1">某服务少部分节点CPU 100%，导致局部RT飙升 <a class="header-anchor" href="#某服务少部分节点cpu-100-导致局部rt飙升" aria-label="Permalink to &quot;某服务少部分节点CPU 100%，导致局部RT飙升&quot;">​</a></h1><h2 id="思路" tabindex="-1">思路 <a class="header-anchor" href="#思路" aria-label="Permalink to &quot;思路&quot;">​</a></h2><ol><li>排查问题节点CPU 100%的表面原因</li></ol><p>引起节点CPU打满的原因有很多，经排查线上监控各指标情况最终确认，<strong>问题节点YGC次数和总时长大于正常节点</strong>，其余指标（如FullGC，线程数等）无明显区别，因此重点分析导致YGC次数飙升的原因</p><blockquote><p>如果从重点指标监控无法分析原因，可能需要使用火焰图等辅助工具来协助分析，此时需要根据具体的DevOps基建来具体分析</p></blockquote><ol start="2"><li>排查线上流量与前期压测流量区别</li></ol><p>因为成本和时间考量，本次压测流量采用的是手动构造方式，怀疑是否流量模型与线上有区别导致单节点出现问题</p><p>分析：流量模型分为3部分构成：请求参数，请求压力（QPS）,流量分布效果，分别进行分析</p><ul><li>请求参数：经采样分析，这部分请求均匀分布，在较大的流量和负载均衡的作用下，近似认为问题节点与其他节点请求参数无明显差别</li><li>请求压力：通过线上监控分析可以判断，问题节点的请求压力与其他节点无明显区别</li><li>流量分布：考虑到手动构造流量与线上实际流量存在差距，且问题场景的并发流量较高，此场景采用的是5分钟1.2W QPS持续流量模型（除此之外还有正态分布，半正态分布等模型），与线上实际流量对比，实际流量为2WQPS持续，除限流量较压测多以外，差别不大，暂时排除</li></ul><p>怀疑有其他原因如CPU资源竞争导致问题节点性能下降，因为压榨过于极限，导致单节点出现问题，此问题仅出现一次，一直无法复现，需要继续观察</p>',10)])])}const C=a(i,[["render",o]]);export{_ as __pageData,C as default};
